def check_market_status(pro):
    """检查市场状态 - 使用交易日历接口"""
    try:
        today = datetime.now().strftime('%Y%m%d')
        # 获取交易日历
        df = pro.trade_cal(exchange='SSE', start_date=today, end_date=today)
        log_api_call('trade_cal', {'exchange': 'SSE', 'start_date': today, 'end_date': today}, len(df))

        if df.empty:
            return False, '休市'

        is_open = df.iloc[0]['is_open'] == '1'

        if not is_open:
            return False, '休市'

        # 检查当前时间是否在交易时间内
        now = datetime.now()
        hour = now.hour
        minute = now.minute

        # 上午交易时间：9:30-11:30
        # 下午交易时间：13:00-15:00
        is_trading_time = (
            (hour == 9 and minute >= 30) or (hour == 10) or (hour == 11 and minute <= 30) or
            (hour == 13) or (hour == 14) or (hour == 15 and minute == 0)
        )

        if is_trading_time:
            return True, '交易中'
        else:
            # 即使在交易日，但不在交易时间内
            if hour < 9 or (hour == 9 and minute < 30):
                return False, '未开盘'
            elif hour > 15 or (hour == 15 and minute > 0):
                return False, '已收盘'
            elif hour == 11 or (hour == 12):
                return False, '午休'
            else:
                return False, '非交易时间'

    except Exception as e:
        log_api_call('trade_cal', {}, 0, 'error', e)
        # 如果无法获取交易日历，默认继续
        return True, '未知 (继续执行)'

